#include "max30102.h"
#include <Wire.h>
static MAX30105 sensor;
static uint32_t _ir=0,_red=0;
static float _bpm=0;
static unsigned long _last=0;
void max30102_setup(){
  Wire.begin();
  if(!sensor.begin(Wire,I2C_SPEED_FAST)){Serial.println("[max30102] Init failed!");return;}
  sensor.setup(60,4,2,400,411,4096);
  Serial.println("[max30102] OK");
}
void max30102_loop(){
  if(millis()-_last<50)return;
  _last=millis();
  _ir=sensor.getIR();
  _red=sensor.getRed();
}
uint32_t max30102_get_ir(){return _ir;}
uint32_t max30102_get_red(){return _red;}
float max30102_get_bpm(){return _bpm;}
